import { type ZodObject } from 'zod';
import { type FormStateResponse } from 'form-state';

import FormDockPanel from './form-dock-panel';

/**
 * Defines what types of errors should be captured.
 *
 * - 'all' - thrown (unhandled) errors and console errors.
 * - 'thrown' - only errors thrown inside the application/form.
 * - 'console' - only errors generated by the `console.error` function.
 * - 'none' - do not capture any errors.
 */
export type CapturedErrorLevel = 'all' | 'console' | 'thrown' | 'none';

/**
 * An error pattern value that can be a `string` or a `RegExp` value.
 *
 * Patterns are used to ignore errors by the `FormDock` component.
 */
export type ErrorPattern = string | RegExp;

/**
 * `FormDock` component props.
 */
export type FormDockProps = Readonly<{
  /**
   * The form state instance.
   */
  form: FormStateResponse<ZodObject>;
  /**
   * Is the application code running in "development" mode?
   *
   * This component if for debugging/observability and should not be rendered
   * in "production" mode.
   *
   * `Only set this property manually if the default component logic is not
   * working correctly in your application.`
   */
  devMode?: boolean;
  /**
   * Should the component be initially rendered in collapsed state? Default: `true`.
   */
  collapsed?: boolean;
  /**
   * Indicates what types of errors should be captured on screen with the error toast?
   *
   * @see {@link CapturedErrorLevel}
   */
  captureErrors?: CapturedErrorLevel;
  /**
   * An array of `string` or `RegExp` values to ignore errors that have a `message` value
   * or a `string` representation that matches one of the patterns.
   *
   * The `collapsed` property value should not be 'none'.
   */
  ignoreErrorPatterns?: ErrorPattern[];
}>;

const EmptyErrorPatterns: ErrorPattern[] = [];

/**
 * A development-only debugging panel that displays detailed information about a form's state.
 *
 * This component renders a form dock only during development or when explicitly enabled via
 * the `devMode` prop. It is completely removed in production builds to avoid any performance impact
 * or exposure of internal form data.
 *
 * @param props - The component props.
 * @param props.form - The current form state response, containing values, errors, touched fields, etc.
 *                     The schema is validated using a Zod object schema.
 * @param props.devMode - Explicitly enable or disable the dock regardless of environment.
 *                        - `true`: always show the dock
 *                        - `false`: never show the dock
 *                        - `undefined`: show only in development environments (default)
 * @param props.collapsed - Is the default state of the dock panel collapsed? Default: `true`.
 * @param props.captureErrors - Should the dock panel display an error toast when an unhandled error is thrown
 *                              or the `console.error` is called? Default: `true`.
 *
 * @returns A form dock component when in development mode, otherwise returns `null`.
 *
 * @example
 * ```tsx
 * <FormDock form={formState} collapsed={false} />
 * ```
 */
function FormDock({
  form,
  devMode,
  collapsed = true,
  captureErrors = 'all',
  ignoreErrorPatterns = EmptyErrorPatterns,
}: FormDockProps) {
  if (devMode === false) {
    return null;
  }

  if (
    devMode === true ||
    (typeof process === 'object' &&
      process.env &&
      process.env['NODE_ENV']?.toLowerCase() === 'development')
  ) {
    return (
      <FormDockPanel
        form={form}
        collapsed={collapsed}
        captureErrors={captureErrors}
        ignoreErrorPatterns={ignoreErrorPatterns}
      />
    );
  }

  return null;
}

export default FormDock;
